class Solution(object):
    def minCost(self, nums, x):
        n = len(nums)
        min_val = nums[:]
        best = sum(nums)
        for r in range(1, n):
            for i in range(n):
                min_val[i] = min(min_val[i], nums[(i - r) % n])
            best = min(best, r * x + sum(min_val))
        return best
